            break
        except:
            continue
    if text is None:
        text = data.decode('latin-1')
    for lineno, line in enumerate(text.splitlines(), 1):
        if pattern.search(line):
            hits.append((f, lineno, line.strip()))
for f, ln, line in hits:
    print(f'{f}:{ln}: {line}')
print(f'\nTotal: {len(hits)} hits in {len(set(h[0] for h in hits))} files')
