pattern = re.compile(r'\bstrtok\s*\(')
file_set = set()
total = 0
for f in files:
    if not os.path.isfile(f):
        continue
    try:
        data = open(f, 'rb').read()
    except:
        continue
    if b'\x00' in data[:512]:
        continue
    text = None
    for enc in ('cp932', 'utf-8'):
        try:
            text = data.decode(enc)
            break
        except:
            continue
    if text is None:
        text = data.decode('latin-1')
    count = 0
    for line in text.splitlines():
        if pattern.search(line):
            count += 1
    if count > 0:
        file_set.add(f)
        total += count
        print(f'{f}: {count} hits')
print(f'\nTotal: {total} hits in {len(file_set)} files')
